@RestController
@RequestMapping("/users")
class UserController {
  @GetMapping("/{id}")
  UserDto get(@PathVariable Long id) {
    return new UserDto(id, "demo@mail.com");
  }
}

record UserDto(Long id, String email) {}

@PostMapping("/users")
public ResponseEntity<UserDto> create(@RequestBody UserCreateRequest req) {
  UserDto saved = service.create(req);
  URI location = URI.create("/users/" + saved.id());
  return ResponseEntity.created(location).body(saved);
}

record UserCreateRequest(
  @NotBlank String fullName,
  @Email @NotBlank String email,
  @Min(18) int age
) {}

@PostMapping("/users")
public ResponseEntity<Void> create(@Valid @RequestBody UserCreateRequest req) {
  return ResponseEntity.status(HttpStatus.CREATED).build();
}

@RestControllerAdvice
class GlobalHandler {
  @ExceptionHandler(MethodArgumentNotValidException.class)
  ResponseEntity<Map<String, String>> handleValidation(MethodArgumentNotValidException ex) {
    Map<String, String> errors = new LinkedHashMap<>();
    ex.getBindingResult().getFieldErrors().forEach(e -> errors.put(e.getField(), e.getDefaultMessage()));
    return ResponseEntity.badRequest().body(errors);
  }
}
